    SAR.add(TARGETPOSX: TARGETPOSX, &fbb)
    SAR.add(TARGETPOSY: TARGETPOSY, &fbb)
    SAR.add(TARGETPOSZ: TARGETPOSZ, &fbb)
    SAR.add(SENALT: SENALT, &fbb)
    SAR.add(SENVELX: SENVELX, &fbb)
    SAR.add(SENVELY: SENVELY, &fbb)
    SAR.add(SENVELZ: SENVELZ, &fbb)
